export const useRestaurantTypes = () => {
  return useQuery({
    queryKey: ["restaurant-types", i18n.language],
    queryFn: () => {
      // Return localized labels for the 9 standardized store types
      return STANDARD_TYPE_KEYS.map(key => getTypeDisplayLabel(key, i18n.language));
    },
  });
};

/**
 * Returns dynamic restaurant types filtered by the active tab.
 * Queries the DB for actual types that exist in restaurants matching the tab criteria,
 * then intersects with STANDARD_TYPE_KEYS to return only relevant filter options.
 */
export const useRestaurantTypesByTab = (tab: string) => {
  return useQuery({
    queryKey: ["restaurant-types-by-tab", tab],
    queryFn: async () => {
      const { data, error } = await supabase.rpc("get_restaurant_types_by_tab", {
        p_tab: tab,
      });
      if (error) throw error;
      const dbTypes = (data as string[]) || [];
      return dbTypes.filter(t => t && t.trim() !== '').sort();
    },
    staleTime: 1000 * 60 * 5,
    gcTime: 1000 * 60 * 15,
  });
};

