export interface TypeGroup {
  key: string;
  label: Record<string, string>;
  tags: string[];
}

const GROUP_LABELS: Record<string, Record<string, string>> = {
  cuisine: { zh: '菜系', en: 'Cuisine', pt: 'Cozinha', ja: '料理', ko: '요리', fr: 'Cuisine', de: 'Küche', es: 'Cocina', it: 'Cucina', ar: 'المطبخ', ru: 'Кухня' },
  store: { zh: '店铺类型', en: 'Store Type', pt: 'Tipo de Loja', ja: '店舗タイプ', ko: '매장 유형', fr: 'Type', de: 'Geschäftstyp', es: 'Tipo', it: 'Tipo', ar: 'نوع المتجر', ru: 'Тип' },
  landmark: { zh: '地标类型', en: 'Landmark Type', pt: 'Tipo de Marco', ja: 'ランドマーク', ko: '랜드마크', fr: 'Type de Monument', de: 'Wahrzeichen', es: 'Tipo de Monumento', it: 'Tipo', ar: 'نوع المعلم', ru: 'Тип' },
  michelin: { zh: '米其林标签', en: 'Michelin Tags', pt: 'Tags Michelin', ja: 'ミシュランタグ', ko: '미슐랭 태그', fr: 'Tags Michelin', de: 'Michelin Tags', es: 'Tags Michelin', it: 'Tag Michelin', ar: 'علامات ميشلان', ru: 'Теги Мишлен' },
  other: { zh: '其他', en: 'Other', pt: 'Outro', ja: 'その他', ko: '기타', fr: 'Autre', de: 'Sonstige', es: 'Otro', it: 'Altro', ar: 'أخرى', ru: 'Другое' },
};

export function groupTypesByCategory(tags: string[], tab?: string): TypeGroup[] {
  const groups: Record<string, string[]> = { cuisine: [], store: [], landmark: [], michelin: [], other: [] };

  for (const tag of tags) {
    if (CUISINE_TAGS.has(tag)) groups.cuisine.push(tag);
    else if (STORE_TAGS.has(tag)) groups.store.push(tag);
    else if (LANDMARK_TAGS.has(tag)) groups.landmark.push(tag);
    else if (MICHELIN_TAGS.has(tag)) groups.michelin.push(tag);
    else groups.other.push(tag);
  }

  // Filter groups based on tab context
  const excludedGroups = new Set<string>();
  if (tab === 'landmark') {
    // Landmarks tab: hide cuisine, store, michelin groups
    excludedGroups.add('cuisine');
    excludedGroups.add('store');
    excludedGroups.add('michelin');
  } else if (tab === 'michelin' || tab === 'food') {
    // Michelin/Food tabs: hide landmark group
    excludedGroups.add('landmark');
  }

  const result: TypeGroup[] = [];
  for (const key of ['cuisine', 'store', 'landmark', 'michelin', 'other'] as const) {
    if (groups[key].length > 0 && !excludedGroups.has(key)) {
      result.push({ key, label: GROUP_LABELS[key], tags: groups[key] });
    }
  }
  return result;
}

